import{_ as t,c as a,o as n,a1 as i}from"./chunks/framework.DDNAyvCW.js";const o="/assets/snippets.GLMotAgF.png",h=JSON.parse('{"title":"Command Snippets","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/snippets/index.md","filePath":"docs/terminal/snippets/index.md"}'),s={name:"docs/terminal/snippets/index.md"};function r(l,e,p,d,c,m){return n(),a("div",null,e[0]||(e[0]=[i('<h1 id="command-snippets" tabindex="-1">Command Snippets <a class="header-anchor" href="#command-snippets" aria-label="Permalink to &quot;Command Snippets&quot;">​</a></h1><p>Save frequently used commands as reusable snippets and execute them with a single click from the terminal&#39;s snippet bar.</p><p><img src="'+o+'" alt=""></p><h2 id="how-snippets-work" tabindex="-1">How Snippets Work <a class="header-anchor" href="#how-snippets-work" aria-label="Permalink to &quot;How Snippets Work&quot;">​</a></h2><p>The snippet bar appears above the terminal input area. Each snippet displays a name and an execute button. Click the button to insert the command into the terminal, then press Enter to run it.</p><h2 id="creating-a-snippet" tabindex="-1">Creating a Snippet <a class="header-anchor" href="#creating-a-snippet" aria-label="Permalink to &quot;Creating a Snippet&quot;">​</a></h2><h3 id="step-by-step" tabindex="-1">Step by Step <a class="header-anchor" href="#step-by-step" aria-label="Permalink to &quot;Step by Step&quot;">​</a></h3><ol><li>Open the snippet manager from the snippet bar.</li><li>Click <strong>Create Snippet</strong> (or the &quot;+&quot; button).</li><li>Fill in the fields: <ul><li><strong>Name</strong> -- a short, descriptive label (e.g., &quot;Check disk usage&quot;).</li><li><strong>Group</strong> -- assign the snippet to a group for organization (e.g., &quot;Monitoring&quot;, &quot;Deployment&quot;).</li><li><strong>Command</strong> -- the shell command or multi-command script to execute.</li></ul></li><li>Save the snippet. It now appears in the snippet bar.</li></ol><h3 id="example-snippets" tabindex="-1">Example Snippets <a class="header-anchor" href="#example-snippets" aria-label="Permalink to &quot;Example Snippets&quot;">​</a></h3><p>Here are practical snippets worth creating:</p><table tabindex="0"><thead><tr><th>Name</th><th>Command</th><th>Purpose</th></tr></thead><tbody><tr><td>Disk Usage</td><td><code>df -h</code></td><td>Quick check of filesystem usage</td></tr><tr><td>Top Memory Processes</td><td><code>ps aux --sort=-%mem | head -20</code></td><td>Find the top 20 memory-consuming processes</td></tr><tr><td>Tail App Logs</td><td><code>tail -f /var/log/app/application.log</code></td><td>Live-follow application logs</td></tr><tr><td>Restart Nginx</td><td><code>sudo systemctl restart nginx &amp;&amp; sudo systemctl status nginx</code></td><td>Restart and verify nginx status</td></tr><tr><td>Backup Config</td><td><code>cp /etc/nginx/nginx.conf /etc/nginx/nginx.conf.bak</code></td><td>Back up a config file before editing</td></tr><tr><td>Docker Cleanup</td><td><code>docker system prune -af --volumes</code></td><td>Remove unused Docker images, containers, and volumes</td></tr></tbody></table><h2 id="macro-recording" tabindex="-1">Macro Recording <a class="header-anchor" href="#macro-recording" aria-label="Permalink to &quot;Macro Recording&quot;">​</a></h2><p>Instead of typing commands manually, you can record a sequence of terminal operations and save them as a snippet automatically.</p><h3 id="how-to-record-a-macro" tabindex="-1">How to Record a Macro <a class="header-anchor" href="#how-to-record-a-macro" aria-label="Permalink to &quot;How to Record a Macro&quot;">​</a></h3><ol><li>Click the <strong>Record</strong> button in the snippet bar to start recording.</li><li>Execute the commands you want to capture in the terminal as you normally would.</li><li>Click <strong>Stop Recording</strong> when you are finished.</li><li>Chaterm generates a snippet from the recorded commands.</li><li>Give the snippet a name and group, then save it.</li></ol><p>Macro recording is especially useful for capturing multi-step workflows that you perform regularly, such as deployment sequences or environment setup routines.</p><h2 id="managing-snippets" tabindex="-1">Managing Snippets <a class="header-anchor" href="#managing-snippets" aria-label="Permalink to &quot;Managing Snippets&quot;">​</a></h2><h3 id="command-groups" tabindex="-1">Command Groups <a class="header-anchor" href="#command-groups" aria-label="Permalink to &quot;Command Groups&quot;">​</a></h3><p>Organize snippets into groups to keep them manageable:</p><ul><li><strong>Monitoring</strong> -- system status, logs, resource usage.</li><li><strong>Deployment</strong> -- build, deploy, rollback commands.</li><li><strong>Database</strong> -- backup, restore, query commands.</li><li><strong>Networking</strong> -- connectivity checks, firewall rules.</li></ul><h3 id="editing-and-deleting" tabindex="-1">Editing and Deleting <a class="header-anchor" href="#editing-and-deleting" aria-label="Permalink to &quot;Editing and Deleting&quot;">​</a></h3><ul><li>Click on a snippet to edit its name, group, or command.</li><li>Delete snippets you no longer need to keep the snippet bar clean.</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li><strong>Combine with AI.</strong> Use <a href="/docs/terminal/chattoai/">Chat to AI</a> to generate a command, then save it as a snippet for future use.</li><li><strong>Use multi-command snippets.</strong> Chain commands with <code>&amp;&amp;</code> to create reliable multi-step operations (the chain stops if any command fails).</li><li><strong>Name snippets clearly.</strong> Use descriptive names so you can identify them at a glance in the snippet bar.</li><li><strong>Avoid storing secrets.</strong> Never put passwords, tokens, or API keys directly in a snippet. Use environment variables or secret managers instead.</li></ul><div class="warning custom-block"><p class="custom-block-title">Security Notice</p><ul><li>Review snippet commands before executing them, especially after editing.</li><li>Avoid including sensitive information (passwords, tokens) in command snippets.</li><li>Verify destructive commands in a test environment before running them in production.</li><li>Regularly audit your snippets and remove those you no longer need.</li></ul></div>',25)]))}const g=t(s,[["render",r]]);export{h as __pageData,g as default};
